import { z } from "zod";
import { documentSchema } from "@hushkey/service-core";

export const itemsSchema = documentSchema({
  name: z.string().min(1),
  done: z.boolean().default(false),
});

export type Item = z.infer<typeof itemsSchema>;

import { SqliteService } from "@hushkey/sqlite-service";
import { sqliteDb } from "../connections.ts";
import { type Item, itemsSchema } from "./items.schema.ts";

export class ItemsService extends SqliteService<Item> {
  constructor() {
    super(sqliteDb, itemsSchema, { collectionName: "items" });
  }

  pending() {
    return this.find({ query: { done: false } });
  }
}

export const itemsService = new ItemsService();

import { DatabaseSync } from "node:sqlite";
import type { SqliteDbLike } from "@hushkey/sqlite-service";

export const sqliteDb: SqliteDbLike = new DatabaseSync(
  "./data/app.db",
) as unknown as SqliteDbLike;

const item = await itemsService.create({ name: "Buy milk" }, { executionerId: "api" });
const open = await itemsService.find({ query: { done: false }, sort: { name: 1 }, limit: 25 });
await itemsService.patch(item.id, { done: true }, { executionerId: "api" });
await itemsService.delete(item.id, { executionerId: "api" });        // soft
await itemsService.restore(item.id, { executionerId: "api" });

await blogs.find({
  query: {
    published: true,
    likes: { $gte: 10 },
    "author.role": { $in: ["author", "admin"] },
    $or: [{ slug: "hello" }, { featured: true }],
  },
});

import { studio } from "@hushkey/studio";
import { itemsService } from "./services/items/items.service.ts";
import { usersService } from "./services/users/users.service.ts";

// Dashboard at /studio, JSON API at /studio/api
app.use(studio({ services: { items: itemsService, users: usersService } }));
